#!/usr/bin/env Rscript
args<-commandArgs(trailingOnly=TRUE);get<-function(k){i<-match(k,args);if(is.na(i))stop('Missing ',k);args[i+1]};a<-readRDS(get('--analysis'));out<-get('--outdir');dir.create(file.path(out,'plots'),recursive=TRUE,showWarnings=FALSE);thr<-as.numeric(get('--min-detection-rate'));auto<-tolower(get('--auto-exclude'))=='true'
assay<-function(n)if(inherits(a,'SummarizedExperiment'))SummarizedExperiment::assay(a,n)else a[[n]];b<-assay('beta');d<-assay('detection');call<-colMeans(is.na(d)|d<=.05);qc<-data.frame(sample_id=colnames(b),detection_call_rate=call,missing_beta_rate=colMeans(is.na(b)),median_beta=apply(b,2,median,na.rm=TRUE),stringsAsFactors=FALSE);qc$flag<-ifelse(qc$detection_call_rate<thr,'detection_call_rate','')
write.table(qc,file.path(out,'sample_qc.tsv'),sep='\t',row.names=FALSE,quote=FALSE);ex<-data.frame(sample_id=qc$sample_id,reason=qc$flag,proposed=qc$flag!='',excluded=auto&qc$flag!='');dir.create(file.path(out,'exclusions'),showWarnings=FALSE);write.table(ex,file.path(out,'proposed_exclusions.tsv'),sep='\t',row.names=FALSE,quote=FALSE);write.table(ex[ex$excluded,,drop=FALSE],file.path(out,'final_exclusions.tsv'),sep='\t',row.names=FALSE,quote=FALSE)
valid_probe<-rowSums(is.finite(b))==ncol(b) & apply(b,1,sd)>0;png(file.path(out,'plots','pca.png'));if(ncol(b)>=2 && sum(valid_probe)>=2){pc<-prcomp(t(b[valid_probe,,drop=FALSE]),scale.=TRUE);plot(pc$x[,1],pc$x[,2],xlab='PC1',ylab='PC2',main='Sample PCA');text(pc$x[,1],pc$x[,2],labels=colnames(b),pos=3,cex=.7)}else{plot.new();text(.5,.5,'PCA unavailable: fewer than two complete variable probes or samples')};dev.off()
png(file.path(out,'plots','correlation.png'));if(ncol(b)>=2){heatmap(cor(b,use='pairwise.complete.obs'),main='Sample correlation')}else{plot.new();text(.5,.5,'Correlation unavailable: fewer than two samples')};dev.off()
writeLines(c('<html><body><h1>openSesame cohort QC</h1><p>Samples are flagged by configurable thresholds; they are not removed unless --auto_exclude_samples is true.</p><pre>',paste(capture.output(print(qc)),collapse='\n'),'</pre><p>Sex inference and fingerprinting are intentionally unavailable until a validated EPICv2 method is bundled.</p></body></html>'),file.path(out,'qc_report.html'))
